//
//  ViewsPhoneEntryView.swift
//  souvenir
//
//  Step 1 of phone auth: collect US phone number and request an OTP.
//

import SwiftUI

struct PhoneEntryView: View {
    @ObservedObject var authService: AuthService
    let onCancel: () -> Void

    @State private var rawPhone: String = ""
    @State private var isLoading = false
    @State private var errorMessage: String?
    @FocusState private var fieldFocused: Bool

    private var formattedDisplay: String {
        let digits = rawPhone.filter(\.isNumber)
        switch digits.count {
        case 0:       return ""
        case 1...3:   return "(\(digits)"
        case 4...6:   return "(\(digits.prefix(3))) \(digits.dropFirst(3))"
        default:
            let area = digits.prefix(3)
            let prefix = digits.dropFirst(3).prefix(3)
            let line = digits.dropFirst(6).prefix(4)
            return "(\(area)) \(prefix)-\(line)"
        }
    }

    var body: some View {
        NavigationStack {
            VStack(spacing: 0) {
                Spacer()

                VStack(spacing: DesignTokens.Spacing.large) {
                    Image(systemName: "phone.fill")
                        .font(.system(size: 44))
                        .foregroundStyle(.accent)

                    VStack(spacing: DesignTokens.Spacing.small) {
                        Text("Verify your number")
                            .font(.title2.weight(.semibold))
                        Text("We'll send you a one-time code to confirm your identity before sharing.")
                            .font(.subheadline)
                            .foregroundStyle(.secondary)
                            .multilineTextAlignment(.center)
                            .padding(.horizontal, DesignTokens.Spacing.large)
                    }

                    // Hidden TextField drives keyboard + text state
                    TextField("", text: Binding(
                        get: { rawPhone },
                        set: { newValue in
                            rawPhone = String(newValue.filter(\.isNumber).prefix(10))
                        }
                    ))
                    .keyboardType(.phonePad)
                    .focused($fieldFocused)
                    .frame(width: 0, height: 0)
                    .opacity(0)
                    .accessibilityHidden(true)

                    // Visual phone display
                    Button {
                        fieldFocused = true
                    } label: {
                        HStack(spacing: DesignTokens.Spacing.small) {
                            Text("+1")
                                .foregroundStyle(.secondary)
                            Text(formattedDisplay.isEmpty ? "(555) 000-0000" : formattedDisplay)
                                .foregroundStyle(formattedDisplay.isEmpty ? .tertiary : .primary)
                        }
                        .font(.title3.weight(.medium).monospacedDigit())
                        .padding(.horizontal, DesignTokens.Spacing.large)
                        .padding(.vertical, DesignTokens.Spacing.medium)
                        .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.medium, style: .continuous))
                        .overlay(
                            RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.medium, style: .continuous)
                                .strokeBorder(fieldFocused ? Color.accentSvnr : Color.clear, lineWidth: 1.5)
                        )
                    }
                    .buttonStyle(.plain)

                    if let error = errorMessage {
                        Text(error)
                            .font(.footnote)
                            .foregroundStyle(.red)
                            .multilineTextAlignment(.center)
                    }

                    Button {
                        sendCode()
                    } label: {
                        Group {
                            if isLoading {
                                ProgressView()
                                    .tint(.white)
                            } else {
                                Text("Send Code")
                                    .font(.body.weight(.semibold))
                            }
                        }
                        .frame(maxWidth: .infinity)
                        .padding(.vertical, DesignTokens.Spacing.medium)
                    }
                    .buttonStyle(.borderedProminent)
                    .disabled(rawPhone.filter(\.isNumber).count < 10 || isLoading)
                }
                .padding(DesignTokens.Spacing.large)

                Spacer()

                Text("Standard message rates may apply.")
                    .font(.caption2)
                    .foregroundStyle(.tertiary)
                    .padding(.bottom, DesignTokens.Spacing.large)
            }
            .navigationTitle("")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel", action: onCancel)
                }
            }
            .onAppear { fieldFocused = true }
        }
    }

    private func sendCode() {
        errorMessage = nil
        isLoading = true
        Task {
            do {
                try await authService.startVerification(phone: rawPhone)
            } catch let error as AuthError {
                errorMessage = error.localizedDescription
            } catch {
                errorMessage = error.localizedDescription
            }
            isLoading = false
        }
    }
}

