//
//  ServicesAuthService.swift
//  souvenir
//
//  Manages phone-number auth with the svnr-api backend.
//  Stores access + refresh tokens in Keychain.
//  Triggered progressively: only when the user attempts to share a souvenir.
//

import Foundation
import Combine

/// Phone auth flow errors surfaced to UI.
enum AuthError: LocalizedError {
    case invalidPhone
    case networkFailure(String)
    case invalidOTP
    case sessionExpired

    var errorDescription: String? {
        switch self {
        case .invalidPhone:    return "Enter a valid US phone number."
        case .networkFailure(let msg): return msg
        case .invalidOTP:      return "Incorrect code. Please try again."
        case .sessionExpired:  return "Session expired. Please sign in again."
        }
    }
}

/// Auth state observed by the UI.
enum AuthState: Equatable {
    case unauthenticated
    case awaitingOTP(phone: String)
    case authenticated
}

@MainActor
final class AuthService: ObservableObject {

    static let shared = AuthService()

    @Published private(set) var state: AuthState = .unauthenticated

    // MARK: - Private

    private let baseURL = "https://auth.kerry.ink/v1"
    private let accessKey  = "auth.accessToken"
    private let refreshKey = "auth.refreshToken"

    private init() {
        if Keychain.load(forKey: accessKey) != nil {
            state = .authenticated
        }
    }

    // MARK: - Public API

    var isAuthenticated: Bool { state == .authenticated }

    /// Step 1 — request an OTP for the given phone number.
    func startVerification(phone: String) async throws {
        let normalized = normalizePhone(phone)
        guard !normalized.isEmpty else { throw AuthError.invalidPhone }

        let body: [String: String] = ["phone": normalized]
        let _: EmptyResponse = try await post("/auth/start", body: body)
        state = .awaitingOTP(phone: normalized)
    }

    /// Step 2 — submit the 6-digit code. Stores tokens on success.
    func confirmCode(_ otp: String, phone: String) async throws {
        let body: [String: String] = ["phone": phone, "code": otp]
        let response: VerifyResponse = try await post("/auth/verify", body: body)
        Keychain.save(response.accessToken, forKey: accessKey)
        Keychain.save(response.refreshToken, forKey: refreshKey)
        state = .authenticated
    }

    /// Proactively refresh the access token if we have a stored refresh token.
    func refreshIfNeeded() async throws {
        guard let refresh = Keychain.load(forKey: refreshKey) else {
            state = .unauthenticated
            throw AuthError.sessionExpired
        }
        let body: [String: String] = ["refresh_token": refresh]
        let response: RefreshResponse = try await post("/auth/refresh", body: body)
        Keychain.save(response.accessToken, forKey: accessKey)
        state = .authenticated
    }

    func signOut() async {
        if let access = Keychain.load(forKey: accessKey) {
            try? await delete("/auth/session", accessToken: access)
        }
        Keychain.delete(forKey: accessKey)
        Keychain.delete(forKey: refreshKey)
        state = .unauthenticated
    }

    // MARK: - Helpers

    private func normalizePhone(_ input: String) -> String {
        let digits = input.filter(\.isNumber)
        guard digits.count >= 10 else { return "" }
        let last10 = String(digits.suffix(10))
        return "+1\(last10)"
    }

    // MARK: - Network

    private func post<Body: Encodable, Response: Decodable>(
        _ path: String,
        body: Body,
        accessToken: String? = nil
    ) async throws -> Response {
        guard let url = URL(string: baseURL + path) else {
            throw AuthError.networkFailure("Bad URL")
        }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        if let token = accessToken ?? Keychain.load(forKey: accessKey) {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        request.httpBody = try JSONEncoder().encode(body)

        let (data, response) = try await URLSession.shared.data(for: request)
        return try handleResponse(data: data, response: response)
    }

    private func delete(_ path: String, accessToken: String) async throws {
        guard let url = URL(string: baseURL + path) else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "DELETE"
        request.setValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")
        _ = try? await URLSession.shared.data(for: request)
    }

    private func handleResponse<T: Decodable>(data: Data, response: URLResponse) throws -> T {
        guard let http = response as? HTTPURLResponse else {
            throw AuthError.networkFailure("No response")
        }
        switch http.statusCode {
        case 200...299:
            if T.self == EmptyResponse.self {
                return EmptyResponse() as! T
            }
            return try JSONDecoder().decode(T.self, from: data)
        case 400, 422:
            throw AuthError.invalidPhone
        case 401:
            throw AuthError.invalidOTP
        default:
            let msg = (try? JSONDecoder().decode(ErrorResponse.self, from: data))?.error
                ?? "Server error (\(http.statusCode))"
            throw AuthError.networkFailure(msg)
        }
    }
}

// MARK: - Response types

private struct VerifyResponse: Decodable {
    let accessToken: String
    let refreshToken: String

    enum CodingKeys: String, CodingKey {
        case accessToken = "access_token"
        case refreshToken = "refresh_token"
    }
}

private struct RefreshResponse: Decodable {
    let accessToken: String

    enum CodingKeys: String, CodingKey {
        case accessToken = "access_token"
    }
}

private struct ErrorResponse: Decodable {
    let error: String
}

private struct EmptyResponse: Codable {}

