//
//  ViewsOTPConfirmView.swift
//  souvenir
//
//  Step 2 of phone auth: enter the 6-digit OTP received via SMS.
//

import SwiftUI

struct OTPConfirmView: View {
    @ObservedObject var authService: AuthService
    let phone: String
    let onSuccess: () -> Void
    let onBack: () -> Void

    @State private var digits: [String] = Array(repeating: "", count: 6)
    @State private var focusedIndex: Int? = 0
    @State private var isVerifying = false
    @State private var isResending = false
    @State private var errorMessage: String?
    @State private var resendCooldown: Int = 0
    @FocusState private var keyboardActive: Bool

    private var otp: String { digits.joined() }
    private var isComplete: Bool { otp.count == 6 }

    var body: some View {
        NavigationStack {
            VStack(spacing: 0) {
                Spacer()

                VStack(spacing: DesignTokens.Spacing.large) {
                    Image(systemName: "lock.shield.fill")
                        .font(.system(size: 44))
                        .foregroundStyle(.accent)

                    VStack(spacing: DesignTokens.Spacing.small) {
                        Text("Check your messages")
                            .font(.title2.weight(.semibold))
                        Text("Enter the 6-digit code sent to \(formattedPhone).")
                            .font(.subheadline)
                            .foregroundStyle(.secondary)
                            .multilineTextAlignment(.center)
                    }

                    // 6-box OTP input
                    HStack(spacing: DesignTokens.Spacing.small) {
                        ForEach(0..<6) { index in
                            OTPDigitBox(
                                digit: digits[index],
                                isFocused: focusedIndex == index,
                                onTap: {
                                    focusedIndex = index
                                    keyboardActive = true
                                }
                            )
                        }
                    }
                    .background(
                        // Hidden unified text field captures keyboard input
                        TextField("", text: Binding(
                            get: { otp },
                            set: { handleInput($0) }
                        ))
                        .keyboardType(.numberPad)
                        .focused($keyboardActive)
                        .frame(width: 1, height: 1)
                        .opacity(0.001)
                        .allowsHitTesting(false)
                    )
                    .onTapGesture { keyboardActive = true }

                    if let error = errorMessage {
                        Text(error)
                            .font(.footnote)
                            .foregroundStyle(.red)
                            .multilineTextAlignment(.center)
                    }

                    Button {
                        verify()
                    } label: {
                        Group {
                            if isVerifying {
                                ProgressView().tint(.white)
                            } else {
                                Text("Verify")
                                    .font(.body.weight(.semibold))
                            }
                        }
                        .frame(maxWidth: .infinity)
                        .padding(.vertical, DesignTokens.Spacing.medium)
                    }
                    .buttonStyle(.borderedProminent)
                    .disabled(!isComplete || isVerifying)

                    // Resend
                    Button {
                        resend()
                    } label: {
                        if resendCooldown > 0 {
                            Text("Resend in \(resendCooldown)s")
                                .font(.subheadline)
                                .foregroundStyle(.tertiary)
                        } else if isResending {
                            ProgressView()
                        } else {
                            Text("Resend code")
                                .font(.subheadline)
                                .foregroundStyle(Color.accentSvnr)
                        }
                    }
                    .disabled(resendCooldown > 0 || isResending)
                }
                .padding(DesignTokens.Spacing.large)

                Spacer()
            }
            .navigationTitle("")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Back", action: onBack)
                }
            }
            .onAppear {
                focusedIndex = 0
                keyboardActive = true
                startResendCooldown(seconds: 30)
            }
        }
    }

    // MARK: - Helpers

    private var formattedPhone: String {
        let d = phone.filter(\.isNumber)
        guard d.count >= 10 else { return phone }
        let last10 = String(d.suffix(10))
        let area = last10.prefix(3)
        let pre  = last10.dropFirst(3).prefix(3)
        let line = last10.dropFirst(6).prefix(4)
        return "(\(area)) \(pre)-\(line)"
    }

    private func handleInput(_ value: String) {
        let cleaned = String(value.filter(\.isNumber).prefix(6))
        digits = (0..<6).map { i in
            i < cleaned.count ? String(cleaned[cleaned.index(cleaned.startIndex, offsetBy: i)]) : ""
        }
        focusedIndex = min(cleaned.count, 5)
        if cleaned.count == 6 { verify() }
    }

    private func verify() {
        guard isComplete, !isVerifying else { return }
        errorMessage = nil
        isVerifying = true
        Task {
            do {
                try await authService.confirmCode(otp, phone: phone)
                onSuccess()
            } catch let error as AuthError {
                errorMessage = error.localizedDescription
                // Clear code on wrong OTP
                if case .invalidOTP = error {
                    digits = Array(repeating: "", count: 6)
                    focusedIndex = 0
                }
            } catch {
                errorMessage = error.localizedDescription
            }
            isVerifying = false
        }
    }

    private func resend() {
        isResending = true
        errorMessage = nil
        Task {
            do {
                try await authService.startVerification(phone: phone)
                startResendCooldown(seconds: 60)
            } catch let error as AuthError {
                errorMessage = error.localizedDescription
            } catch {
                errorMessage = error.localizedDescription
            }
            isResending = false
        }
    }

    private func startResendCooldown(seconds: Int) {
        resendCooldown = seconds
        Timer.scheduledTimer(withTimeInterval: 1, repeats: true) { timer in
            resendCooldown -= 1
            if resendCooldown <= 0 { timer.invalidate() }
        }
    }
}

// MARK: - Digit box

private struct OTPDigitBox: View {
    let digit: String
    let isFocused: Bool
    let onTap: () -> Void

    var body: some View {
        Text(digit.isEmpty ? " " : digit)
            .font(.title.weight(.semibold).monospacedDigit())
            .frame(width: 44, height: 56)
            .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.small, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.small, style: .continuous)
                    .strokeBorder(isFocused ? Color.accentSvnr : Color.clear, lineWidth: 2)
            )
            .contentShape(Rectangle())
            .onTapGesture(perform: onTap)
    }
}

//
//  ContentView.swift
//  souvenir
//
//  Created by Kerry on 14.01.2026.
//

import SwiftUI
import UIKit
import CoreData
import PhotosUI
import CoreLocation
import CloudKit

struct ContentView: View {
    @Environment(\.managedObjectContext) private var viewContext
    @StateObject private var router = Router()
    @StateObject private var newSouvenirTracker = NewSouvenirTracker()
    var eeliotEngine: EeliotEngine?

    private let shareService = ShareService.shared

    // Phase 11: Bottom nav state
    @State private var viewMode: MainViewMode = .timeline
    @AppStorage("svnrLastViewMode") private var storedViewModeRaw: String = MainViewMode.timeline.rawValue

    // Added @State variables as per instructions
    @State private var showCamera = false
    @State private var capturedImage: UIImage? = nil
    @State private var capturedLocation: CLLocation? = nil
    @State private var selectedPhoto: PhotosPickerItem? = nil
    @State private var isOnboardingFlow = false
    @State private var pendingLibraryNavigation = false

    @State private var isKeyboardVisible = false
    @State private var pendingOnboardingCamera = false

    // Share sheet state — presented at ContentView level so it isn't nested inside fullScreenCover
    @State private var souvenirToShare: SouvenirEntity?
    @State private var showShareSheet = false

    // Phone auth — presented when .svnrRequestShare fires and user is not authenticated
    @ObservedObject private var authService = AuthService.shared
    @State private var showAuthFlow = false

    // Phase 12: Dark mode support
    @Environment(\.colorScheme) private var colorScheme

    @State private var focusSidebarVisible: Bool = true
    @State private var mapFocusedSouvenirID: UUID?
    @State private var mapFocusedLatitude: Double?
    @State private var mapFocusedLongitude: Double?
    @State private var mapFocusedPhotoAssetId: String?
    @State private var mapFocusedPhotoID: UUID?
    @State private var mapSuppressDetailSheet: Bool = false
    @State private var mapInitialIslandState: ContactIslandState = .compact
    @State private var mapFocusToken = UUID()
    @State private var mapLocationSearchContext: LocationSearchContext?
    @State private var mapDidApplyLocationSelection: Bool = false
    @State private var pendingLocationReturnRoute: Route?
    @State private var pendingDraftSouvenirID: UUID?
    @State private var preserveNewSouvenirInputs: Bool = false
    @AppStorage("svnrHasSavedFirstSouvenir") private var hasSavedFirstSouvenir = false
    @AppStorage("svnrAccentHex") private var svnrAccentHex: String?
    @Namespace private var transitionNamespace

    private var accentColor: Color {
        _ = svnrAccentHex
        return Color.accentSvnr
    }

    var body: some View {
        baseContent
            .environmentObject(router)
            .environmentObject(newSouvenirTracker)
            .navigationViewStyle(.stack)
            .onAppear {
                newSouvenirTracker.eeliotEngine = eeliotEngine
            }
            .modifier(ContentLifecycleModifier(viewContext: viewContext, newSouvenirTracker: newSouvenirTracker, handleUniversalLink: handleUniversalLink))
            .modifier(RouteChangeModifier(
                selectedPhoto: $selectedPhoto,
                isOnboardingFlow: $isOnboardingFlow,
                router: router,
                newSouvenirTracker: newSouvenirTracker,
                viewMode: $viewMode,
                mapFocusedSouvenirID: $mapFocusedSouvenirID,
                mapFocusedLatitude: $mapFocusedLatitude,
                mapFocusedLongitude: $mapFocusedLongitude,
                mapFocusedPhotoAssetId: $mapFocusedPhotoAssetId,
                mapFocusedPhotoID: $mapFocusedPhotoID,
                mapSuppressDetailSheet: $mapSuppressDetailSheet,
                mapInitialIslandState: $mapInitialIslandState
            ))
            .modifier(KeyboardVisibilityModifier(isKeyboardVisible: $isKeyboardVisible))
            .modifier(NotificationObserverModifier(
                pendingOnboardingCamera: $pendingOnboardingCamera,
                showCamera: $showCamera,
                showAuthFlow: $showAuthFlow,
                router: router,
                authService: authService,
                dismissFocusView: dismissFocusView
            ))
            .onAppear {
                if let stored = MainViewMode(rawValue: storedViewModeRaw) {
                    viewMode = stored
                }
            }
            .onChange(of: viewMode) { _, newMode in
                storedViewModeRaw = newMode.rawValue
            }
            .onChange(of: selectedPhoto) { _, newValue in
                guard newValue != nil else { return }
                pendingLibraryNavigation = true
                if !showCamera {
                    isOnboardingFlow = true
                    startNewSouvenirFlow()
                    pendingLibraryNavigation = false
                }
            }
            .onChange(of: showCamera) { _, isPresented in
                guard !isPresented, pendingLibraryNavigation, selectedPhoto != nil else { return }
                isOnboardingFlow = true
                startNewSouvenirFlow()
                pendingLibraryNavigation = false
            }
            .onReceive(NotificationCenter.default.publisher(for: .svnrFocusMapOnSouvenir)) { notification in
                guard let souvenirID = notification.userInfo?["souvenirID"] as? UUID else { return }
                let lat = notification.userInfo?["latitude"] as? Double
                let lon = notification.userInfo?["longitude"] as? Double
                let assetId = notification.userInfo?["photoAssetId"] as? String
            let photoID = notification.userInfo?["photoID"] as? UUID

            var focusedLat = lat
            var focusedLon = lon
            var focusedAssetId = assetId

            if let photoID = photoID {
                let request: NSFetchRequest<PhotoEntity> = PhotoEntity.fetchRequest()
                request.fetchLimit = 1
                request.predicate = NSPredicate(format: "id == %@", photoID as CVarArg)
                if let photo = try? viewContext.fetch(request).first {
                    if let photoLat = photo.latitude?.doubleValue,
                       let photoLon = photo.longitude?.doubleValue,
                       !(photoLat == 0.0 && photoLon == 0.0) {
                        focusedLat = photoLat
                        focusedLon = photoLon
                    }
                    if let localId = photo.assetLocalId, !localId.isEmpty {
                        focusedAssetId = localId
                    }
                }
            }

            router.navigateToRoot()
            viewMode = .map
            mapFocusedSouvenirID = souvenirID
            mapFocusedLatitude = focusedLat
            mapFocusedLongitude = focusedLon
            mapFocusedPhotoAssetId = focusedAssetId
            mapFocusedPhotoID = photoID
            mapSuppressDetailSheet = false
            mapInitialIslandState = .compact
            mapFocusToken = UUID()
            mapLocationSearchContext = nil
        }
        .onReceive(NotificationCenter.default.publisher(for: .svnrOpenLocationSearch)) { notification in
            guard let photoID = notification.userInfo?["photoID"] as? UUID else { return }
            let souvenirIDHint = notification.userInfo?["souvenirID"] as? UUID
            let targetRaw = notification.userInfo?["target"] as? String
            let target = LocationSearchTarget(rawValue: targetRaw ?? "") ?? .photoLocation
            let returnToNewSouvenir = notification.userInfo?["returnToNewSouvenir"] as? Bool ?? false

            var souvenirID: UUID?
            var latitude: Double?
            var longitude: Double?
            var assetLocalId: String?

            let request: NSFetchRequest<PhotoEntity> = PhotoEntity.fetchRequest()
            request.fetchLimit = 1
            request.predicate = NSPredicate(format: "id == %@", photoID as CVarArg)

            if let photo = try? viewContext.fetch(request).first {
                latitude = photo.latitude?.doubleValue
                longitude = photo.longitude?.doubleValue
                assetLocalId = photo.assetLocalId

                if let hint = souvenirIDHint,
                   photo.souvenirsArray.contains(where: { $0.id == hint }) {
                    souvenirID = hint
                } else {
                    souvenirID = photo.souvenirsArray.first?.id
                }
            } else {
                souvenirID = souvenirIDHint
            }

            guard let resolvedSouvenirID = souvenirID else { return }

            if returnToNewSouvenir {
                pendingLocationReturnRoute = .souvenirNew
                pendingDraftSouvenirID = resolvedSouvenirID
                preserveNewSouvenirInputs = true
            } else if target == .meetPlace || target == .contactHomeAddress {
                pendingLocationReturnRoute = .souvenir(id: resolvedSouvenirID)
                pendingDraftSouvenirID = nil
            } else {
                pendingLocationReturnRoute = .souvenirPhoto(souvenirID: resolvedSouvenirID, photoID: photoID)
                pendingDraftSouvenirID = nil
            }

            mapLocationSearchContext = LocationSearchContext(
                photoID: photoID,
                souvenirID: resolvedSouvenirID,
                latitude: latitude,
                longitude: longitude,
                assetLocalId: assetLocalId,
                target: target
            )

            router.navigateToRoot()
            viewMode = .map
            mapFocusedSouvenirID = resolvedSouvenirID
            mapFocusedLatitude = latitude
            mapFocusedLongitude = longitude
            mapFocusedPhotoAssetId = assetLocalId
            mapFocusedPhotoID = photoID
            mapSuppressDetailSheet = false
            mapInitialIslandState = .compact
            mapFocusToken = UUID()
        }
        .onChange(of: viewMode) { _, newMode in
            if newMode == .map,
               mapFocusedSouvenirID == nil,
               mapFocusedPhotoID == nil {
                mapLocationSearchContext = nil
                mapInitialIslandState = .compact
            }
        }
        .onChange(of: mapDidApplyLocationSelection) { _, newValue in
            guard newValue else { return }
            mapDidApplyLocationSelection = false
            let returnRoute = pendingLocationReturnRoute
            pendingLocationReturnRoute = nil

            if let route = returnRoute {
                viewMode = .timeline
                router.navigateToRoot()
                router.navigate(to: route)
            }
            preserveNewSouvenirInputs = false
        }
        .onChange(of: newSouvenirTracker.pendingReturnViewMode) { _, newValue in
            guard let mode = newValue else { return }
            newSouvenirTracker.pendingReturnViewMode = nil
            router.navigateToRoot()
            viewMode = mode
        }
        .animation(DesignTokens.Animation.standardSpring, value: viewMode)
        .sheet(isPresented: $showShareSheet, onDismiss: {
            let shared = souvenirToShare
            souvenirToShare = nil
            if let souvenir = shared {
                newSouvenirTracker.trackNewSouvenir(souvenir.id)
            }
            newSouvenirTracker.requestReturnToOrigin()
        }) {
            if let souvenir = souvenirToShare {
                ShareSheet(souvenir: souvenir)
                    .environment(\.managedObjectContext, viewContext)
                    .presentationBackground(.clear)
                    .presentationBackgroundInteraction(.enabled)
            }
        }
        // Phone auth flow — shown when .svnrRequestShare fires and user isn't authenticated
        .sheet(isPresented: $showAuthFlow) {
            authFlowView
        }
        // Updated .fullScreenCover for camera presentation over sheets
        .fullScreenCover(isPresented: $showCamera) {
            CustomCameraView(
                selectedPhoto: $selectedPhoto,
                promptForLocationOnOpen: hasSavedFirstSouvenir,
                onCapture: { image, location in
                    capturedImage = image
                    capturedLocation = location
                    showCamera = false
                    startNewSouvenirFlow()
                },
                onCancel: {
                    showCamera = false
                }
            )
            .environmentObject(router)
            .environmentObject(newSouvenirTracker)
        }
    }

    private var baseContent: some View {
        NavigationStack(path: $router.path) {
            rootContent
        }
        .overlay(alignment: .top) {
            if toolbarIsVisible {
                PersistentToolbar(
                    viewMode: $viewMode,
                    onMapAction: toolbarMapAction,
                    onCenterAction: toolbarCenterAction,
                    onCameraAction: toolbarCameraAction
                )
                .transition(.move(edge: .top).combined(with: .opacity))
            }
        }
    }

    // MARK: - Toolbar helpers

    private var toolbarIsVisible: Bool {
        // Use path.isEmpty so the iOS swipe-back gesture (which updates path directly,
        // bypassing router.currentRoute) correctly restores the toolbar.
        hasSavedFirstSouvenir && !showCamera && router.path.isEmpty
    }

    /// Navigates to map view.
    private var toolbarMapAction: () -> Void {
        {
            NotificationCenter.default.post(name: .svnrShouldHideContactSheet, object: nil)
            viewMode = .map
        }
    }

    /// Navigates to hybrid list view.
    private var toolbarCenterAction: () -> Void {
        {
            NotificationCenter.default.post(name: .svnrShouldHideContactSheet, object: nil)
            viewMode = .timeline
        }
    }

    private var toolbarCameraAction: () -> Void {
        {
            NotificationCenter.default.post(name: .svnrShouldHideContactSheet, object: nil)
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.35) {
                NotificationCenter.default.post(name: .svnrRequestCamera, object: nil)
            }
        }
    }

    @ViewBuilder
    private var rootContent: some View {
        GeometryReader { geometry in
            let bottomInset = geometry.safeAreaInsets.bottom
            ZStack {
                BackgroundView()
                    .ignoresSafeArea()

                Group {
                    if viewMode == .map {
                        mapView()
                    } else {
                        SvnrHybridView(transitionNamespace: transitionNamespace)
                    }
                }
                .navigationDestination(for: Route.self) { route in
                    destinationView(for: route)
                }
                .ignoresSafeArea(edges: .bottom)
                .zIndex(1)
            }
            .tint(accentColor)
            .overlay(
                devToolsFloatingButton
                    .padding(.leading, DesignTokens.Spacing.large)
                    .padding(.bottom, bottomInset + DesignTokens.Spacing.large),
                alignment: .bottomLeading
            )
        }
    }

    private var devToolsFloatingButton: some View {
        Button {
            router.navigate(to: .devTools)
        } label: {
            Image(systemName: "hammer.fill")
                .font(.title3)
                .foregroundStyle(.primary)
                .frame(width: 48, height: 48)
                .background(.ultraThinMaterial, in: Circle())
                .overlay(
                    Circle()
                        .strokeBorder(Color(uiColor: .separator), lineWidth: 1)
                )
        }
        .buttonStyle(.plain)
        .shadow(color: Color.black.opacity(0.25), radius: 8, x: 0, y: 4)
        .accessibilityLabel("Open Dev Tools")
    }

    // MARK: - Map Presentation

    @ViewBuilder
    private func mapView() -> some View {
        SvnrMapView(
            viewMode: $viewMode,
            transitionNamespace: transitionNamespace,
            focusedSouvenirID: mapFocusedSouvenirID,
            focusedLatitude: mapFocusedLatitude,
            focusedLongitude: mapFocusedLongitude,
            focusedPhotoAssetId: mapFocusedPhotoAssetId,
            focusedPhotoID: mapFocusedPhotoID,
            focusToken: mapFocusToken,
            suppressDetailSheet: mapSuppressDetailSheet,
            initialIslandState: mapInitialIslandState,
            locationSearchContext: $mapLocationSearchContext,
            didApplyLocationSelection: $mapDidApplyLocationSelection
        )
    }

    // MARK: - Camera Handling

    private func handleCapturedImage(_ image: UIImage) {
        // Store the captured image and navigate to new souvenir flow
        capturedImage = image
        isOnboardingFlow = pendingOnboardingCamera
        pendingOnboardingCamera = false
        startNewSouvenirFlow()
    }

    private func startNewSouvenirFlow() {
        newSouvenirTracker.setReturnViewMode(viewMode)
        router.navigate(to: .souvenirNew)
    }

    private func handleCameraCancelled() {
        if pendingOnboardingCamera {
            NotificationCenter.default.post(name: .svnrOnboardingCameraCancelled, object: nil)
        }
        pendingOnboardingCamera = false
        isOnboardingFlow = false
    }

    private func dismissFocusView() {
        focusSidebarVisible = true
    }

    /// Auth flow sheet content — advances automatically as AuthService.state changes.
    @ViewBuilder
    private var authFlowView: some View {
        switch authService.state {
        case .unauthenticated:
            PhoneEntryView(
                authService: authService,
                onCancel: { showAuthFlow = false }
            )
        case .awaitingOTP(let phone):
            OTPConfirmView(
                authService: authService,
                phone: phone,
                onSuccess: { showAuthFlow = false },
                onBack: {
                    // Reset to unauthenticated so user can re-enter phone
                    Task { await authService.signOut() }
                }
            )
        case .authenticated:
            // Shouldn't appear; dismiss immediately
            Color.clear.onAppear { showAuthFlow = false }
        }
    }

    @ViewBuilder
    private var souvenirNewDestination: some View {
        if let image = capturedImage {
            AddSouvenirView(
                initialCapturedImage: image,
                initialCapturedLocation: capturedLocation,
                initialSelectedPhoto: nil,
                onReadyToShare: { souvenir in
                    souvenirToShare = souvenir
                    showShareSheet = true
                }
            )
            .onDisappear {
                if !preserveNewSouvenirInputs {
                    resetCreateInputs()
                }
            }
        } else if let item = selectedPhoto {
            AddSouvenirView(
                initialCapturedImage: nil,
                initialCapturedLocation: nil,
                initialSelectedPhoto: item,
                onReadyToShare: { souvenir in
                    souvenirToShare = souvenir
                    showShareSheet = true
                }
            )
            .onDisappear {
                if !preserveNewSouvenirInputs {
                    resetCreateInputs()
                }
            }
        } else {
            EmptyView()
        }
    }

    private func resetCreateInputs() {
        capturedImage = nil
        selectedPhoto = nil
        isOnboardingFlow = false
        capturedLocation = nil
        pendingDraftSouvenirID = nil
    }

    @ViewBuilder
    private func destinationView(for route: Route) -> some View {
        switch route {
        case .souvenirList:
            SvnrHybridView(transitionNamespace: transitionNamespace)

        case .souvenirNew:
            souvenirNewDestination

        case .souvenir(let souvenirID):
            let sorted = fetchSortedSouvenirs()
            Group {
                if let initialIndex = sorted.firstIndex(where: { $0.id == souvenirID }) {
                    let initialSouvenir = sorted[initialIndex]
                    let focusView = SouvenirFocusContainer(
                        initialSouvenir: initialSouvenir,
                        souvenirs: sorted,
                        initialIndex: initialIndex,
                        initialPhotoID: nil,
                        isSidebarVisible: $focusSidebarVisible,
                        onDismiss: {
                            router.navigateBack()
                        }
                    )
                    .environmentObject(newSouvenirTracker)
                    .environmentObject(router)
                    .navigationBarBackButtonHidden(true)
                    .toolbar(.hidden, for: .navigationBar)
                    if #available(iOS 17.0, *) {
                        focusView
                            .navigationTransition(.zoom(sourceID: souvenirID, in: transitionNamespace))
                    } else {
                        focusView
                    }
                } else {
                    EmptyView()
                }
            }

        case .souvenirPhoto(let souvenirID, let photoID):
            let sorted = fetchSortedSouvenirs()
            Group {
                if let initialIndex = sorted.firstIndex(where: { $0.id == souvenirID }) {
                    let initialSouvenir = sorted[initialIndex]
                    let focusView = SouvenirFocusContainer(
                        initialSouvenir: initialSouvenir,
                        souvenirs: sorted,
                        initialIndex: initialIndex,
                        initialPhotoID: photoID,
                        isSidebarVisible: $focusSidebarVisible,
                        onDismiss: {
                            router.navigateBack()
                        }
                    )
                    .environmentObject(newSouvenirTracker)
                    .environmentObject(router)
                    .navigationBarBackButtonHidden(true)
                    .toolbar(.hidden, for: .navigationBar)
                    if #available(iOS 17.0, *) {
                        focusView
                            .navigationTransition(.zoom(sourceID: souvenirID, in: transitionNamespace))
                    } else {
                        focusView
                    }
                } else {
                    EmptyView()
                }
            }

        case .friendMap,
             .friendMapFocused,
             .friendMapAtLocation,
             .friendMapFromFocus:
            EmptyView() // Presented as sheet

        case .contactNew:
            ContactNewView()
        case .contactRings(let contactID):
            ContactRingsView(contactID: contactID)
        case .contactRingAssignment(let contactID):
            if let contact = fetchContact(by: contactID) {
                ContactRingPickerView(contact: contact)
            } else {
                EmptyView()
            }
        case .devTools:
            DevToolsView(container: PersistenceController.shared.container)
        case .settings:
            SettingsView()
        }
    }

    // MARK: - Universal Link Handling

    private func handleUniversalLink(_ url: URL) {
        // Parse token from URL (format: https://souvenir.kerry.ink/s/{token})
        guard let token = shareService.parseToken(from: url) else {
            print("[UniversalLink] Invalid URL format: \(url)")
            return
        }

        // Validate token and get souvenir
        guard let souvenir = shareService.validateToken(token, in: viewContext) else {
            print("[UniversalLink] Invalid or expired token: \(token)")
            return
        }

        // Navigate to souvenir focus view
        router.navigateToRoot()
        router.navigate(to: .souvenir(id: souvenir.id))

        print("[UniversalLink] Opened souvenir: \(souvenir.displayTitle)")
    }

    private func fetchSouvenir(id: UUID) -> SouvenirEntity? {
        let request = SouvenirEntity.fetchRequest()
        request.predicate = NSCompoundPredicate(andPredicateWithSubpredicates: [
            SouvenirEntity.activePredicate,
            NSPredicate(format: "id == %@", id as CVarArg)
        ])
        request.fetchLimit = 1
        return try? viewContext.fetch(request).first
    }

    private func fetchContact(by id: UUID) -> ContactEntity? {
        let request = ContactEntity.fetchRequest()
        request.predicate = NSPredicate(format: "id == %@", id as CVarArg)
        request.fetchLimit = 1
        return try? viewContext.fetch(request).first
    }

    @MainActor
    private func fetchSortedSouvenirs() -> [SouvenirEntity] {
        let request = SouvenirEntity.fetchRequest()
        request.predicate = SouvenirEntity.activePredicate
        guard let results = try? viewContext.fetch(request) else {
            return []
        }
        return results.sorted(by: SouvenirEntity.byFrecencyDescending)
    }

}

private struct ContentLifecycleModifier: ViewModifier {
    let viewContext: NSManagedObjectContext
    let newSouvenirTracker: NewSouvenirTracker
    let handleUniversalLink: (URL) -> Void

    func body(content: Content) -> some View {
        content
            .onAppear {
                viewContext.userInfo["newSouvenirTracker"] = newSouvenirTracker
            }
            .onOpenURL { url in
                handleUniversalLink(url)
            }
    }
}

private struct CameraCoverModifier: ViewModifier {
    @Binding var showCamera: Bool
    @Binding var selectedPhoto: PhotosPickerItem?
    let handleCapturedImage: (UIImage) -> Void
    let handleCameraCancelled: () -> Void

    func body(content: Content) -> some View {
        content
            .fullScreenCover(isPresented: $showCamera) {
                CustomCameraView(
                    selectedPhoto: $selectedPhoto,
                    onCapture: { image, location in
                        handleCapturedImage(image)
                    },
                    onCancel: {
                        handleCameraCancelled()
                    }
                )
            }
    }
}

private struct RouteChangeModifier: ViewModifier {
    @Binding var selectedPhoto: PhotosPickerItem?
    @Binding var isOnboardingFlow: Bool
    @ObservedObject var router: Router
    @ObservedObject var newSouvenirTracker: NewSouvenirTracker
    @Binding var viewMode: MainViewMode
    @Binding var mapFocusedSouvenirID: UUID?
    @Binding var mapFocusedLatitude: Double?
    @Binding var mapFocusedLongitude: Double?
    @Binding var mapFocusedPhotoAssetId: String?
    @Binding var mapFocusedPhotoID: UUID?
    @Binding var mapSuppressDetailSheet: Bool
    @Binding var mapInitialIslandState: ContactIslandState

    func body(content: Content) -> some View {
        content
            .onChange(of: router.currentRoute) { _, newRoute in
                if let newRoute = newRoute {
                    switch newRoute {
                    case .friendMap, .friendMapFocused, .friendMapAtLocation, .friendMapFromFocus:
                        viewMode = .map
                        switch newRoute {
                        case .friendMap:
                            mapFocusedSouvenirID = nil
                            mapFocusedLatitude = nil
                            mapFocusedLongitude = nil
                            mapFocusedPhotoAssetId = nil
                            mapFocusedPhotoID = nil
                            mapSuppressDetailSheet = false
                        case .friendMapFocused(let souvenirID, let islandState):
                            mapFocusedSouvenirID = souvenirID
                            mapFocusedLatitude = nil
                            mapFocusedLongitude = nil
                            mapFocusedPhotoAssetId = nil
                            mapFocusedPhotoID = nil
                            mapSuppressDetailSheet = (islandState != .fullSheet)
                            mapInitialIslandState = islandState
                        case .friendMapAtLocation(let souvenirID, let latitude, let longitude):
                            mapFocusedSouvenirID = souvenirID
                            mapFocusedLatitude = latitude
                            mapFocusedLongitude = longitude
                            mapFocusedPhotoAssetId = nil
                            mapFocusedPhotoID = nil
                            mapSuppressDetailSheet = false
                        case .friendMapFromFocus(let souvenirID, let latitude, let longitude):
                            mapFocusedSouvenirID = souvenirID
                            mapFocusedLatitude = latitude
                            mapFocusedLongitude = longitude
                            mapFocusedPhotoAssetId = nil
                            mapFocusedPhotoID = nil
                            mapSuppressDetailSheet = true
                        default:
                            break
                        }
                    case .souvenirList:
                        viewMode = .timeline
                    case .souvenir:
                        viewMode = .timeline
                    case .souvenirPhoto:
                        viewMode = .timeline
                    default:
                        break
                    }
                }
            }
    }
}

private struct KeyboardVisibilityModifier: ViewModifier {
    @Binding var isKeyboardVisible: Bool

    func body(content: Content) -> some View {
        content
            .onReceive(NotificationCenter.default.publisher(for: UIResponder.keyboardWillShowNotification)) { _ in
                withAnimation(.easeInOut(duration: 0.2)) {
                    isKeyboardVisible = true
                }
            }
            .onReceive(NotificationCenter.default.publisher(for: UIResponder.keyboardWillHideNotification)) { _ in
                withAnimation(.easeInOut(duration: 0.2)) {
                    isKeyboardVisible = false
                }
            }
    }
}

private struct NotificationObserverModifier: ViewModifier {
    @Binding var pendingOnboardingCamera: Bool
    @Binding var showCamera: Bool
    @Binding var showAuthFlow: Bool
    @ObservedObject var router: Router
    @ObservedObject var authService: AuthService
    let dismissFocusView: () -> Void

    func body(content: Content) -> some View {
        content
        .onReceive(NotificationCenter.default.publisher(for: .svnrDismissFocusView)) { _ in
            dismissFocusView()
        }
        .onReceive(NotificationCenter.default.publisher(for: .svnrFocusSouvenir)) { notification in
            if let id = notification.userInfo?["souvenirID"] as? UUID {
                if let photoID = notification.userInfo?["photoID"] as? UUID {
                    router.navigate(to: .souvenirPhoto(souvenirID: id, photoID: photoID))
                } else {
                    router.navigate(to: .souvenir(id: id))
                }
            }
        }
        .onReceive(NotificationCenter.default.publisher(for: .svnrRequestCamera)) { _ in
            pendingOnboardingCamera = true
            showCamera = true
        }
        .onReceive(NotificationCenter.default.publisher(for: .svnrRequestShare)) { _ in
            guard !authService.isAuthenticated else { return }
            showAuthFlow = true
        }
    }
}

