    34→
    35→    // Self's bonds sorted by manual ring order; contact must have a souvenir
    36→    @FetchRequest(
    37→        sortDescriptors: [NSSortDescriptor(keyPath: \BondEntity.ringOrder, ascending: true)],
    38→        predicate: NSPredicate(format: "owner.isSelf == YES AND contact.primarySouvenir != nil"),
    39→        animation: nil
    40→    )
    41→    private var bonds: FetchedResults<BondEntity>
    42→
    43→    @FetchRequest(
    44→        sortDescriptors: [],
    45→        predicate: NSPredicate(format: "isSelf == YES"),
    46→        animation: nil
    47→    )
    48→    private var selfContacts: FetchedResults<ContactEntity>
    49→
    50→    @State private var favoriteBackgroundImage: UIImage?
    51→    @State private var favoriteBackgroundAssetId: String?
    52→    @State private var showAmbientGlyphLineTrace: Bool = false
    53→    @State private var openRowID: UUID? = nil
