    55→    // MARK: - Drag reorder state
    56→    @State private var draggingID: UUID? = nil
    57→    @State private var draggingFromIndex: Int = 0
    58→    @State private var reorderOffset: CGFloat = 0
    59→    /// Approximate row height used to compute how many slots the drag crossed.
    60→    private let rowHeight: CGFloat = 324
    61→
    62→    private let photoLoader = PhotoLoadingService()
    63→
    64→    // MARK: - Computed lists
    65→
    66→    @MainActor
    67→    private var sortedSouvenirs: [SouvenirEntity] {
