    73→    private var orderedBonds: [BondEntity] {
    74→        bonds.sorted { $0.ringOrder < $1.ringOrder }
    75→    }
    76→
    77→    /// Falls back to frecency order when no BondEntity records exist.
    78→    private var ringItems: [RingItem] {
