   121→    // MARK: - List view
   122→    // Uses ScrollView + LazyVStack so the horizontal DragGesture in SvnrCapsuleRow
   123→    // does not compete with UITableView's pan gesture recognizer.
   124→
   125→    private var listView: some View {
