   145→                            onReorderStart: { startReorder(id: item.souvenir.id, fromIndex: index) },
   146→                            onReorderUpdate: { dy in reorderOffset = dy },
   147→                            onReorderEnd: { dy in commitReorder(finalOffset: dy) }
   148→                        )
   149→                        .padding(.horizontal, 16)
