   152→                    }
   153→
   154→                    // Trailing add-placeholder
   155→                    AddSouvenirCapsuleView()
   156→                        .padding(.horizontal, 16)
   157→                        .padding(.vertical, 6)
   158→                        .opacity(0.7)
   159→
   160→                    // Ambient glyph footer
   161→                    AmbientGlyph(
