   168→                            }
   169→                        }
   170→                    )
   171→                    .padding(.vertical, DesignTokens.Spacing.jumbo)
   172→                    .frame(maxWidth: .infinity)
   173→                }
   174→            }
   175→        }
   176→    }
   177→
   178→    // MARK: - Drag-to-reorder
   179→
   180→    private func startReorder(id: UUID, fromIndex: Int) {
   181→        guard draggingID == nil else { return }
   182→        openRowID = nil          // close any open drawer
   183→        draggingID = id
   184→        draggingFromIndex = fromIndex
   185→        reorderOffset = 0
   186→    }
   187→
   188→    /// Y offset to show for each row while a drag is in progress.
   189→    /// The grabbed row follows the drag; neighbours shift to reveal the insertion slot.
   190→    private func rowDisplayOffset(for id: UUID, at index: Int) -> CGFloat {
   191→        guard let _ = draggingID else { return 0 }
   192→        if id == draggingID { return reorderOffset }
   193→        let toIndex = insertionIndex
   194→        let from = draggingFromIndex
   195→        if from < toIndex {
   196→            if index > from && index <= toIndex { return -rowHeight }
   197→        } else if from > toIndex {
   198→            if index >= toIndex && index < from { return rowHeight }
   199→        }
   200→        return 0
   201→    }
   202→
   203→    private var insertionIndex: Int {
   204→        let steps = Int((reorderOffset / rowHeight).rounded())
   205→        return max(0, min(ringItems.count - 1, draggingFromIndex + steps))
   206→    }
   207→
   208→    private func commitReorder(finalOffset: CGFloat) {
   209→        let to = insertionIndex
   210→        let from = draggingFromIndex
   211→
   212→        // Clear drag state first so the snap animation plays cleanly
   213→        withAnimation(.spring(response: 0.35, dampingFraction: 0.75)) {
   214→            draggingID = nil
   215→            reorderOffset = 0
   216→        }
   217→
   218→        guard from != to, let owner = selfContact else { return }
   219→        let service = RingOrderService(viewContext: viewContext, owner: owner)
   220→        var mutable = orderedBonds
   221→        mutable.move(fromOffsets: IndexSet(integer: from), toOffset: to > from ? to + 1 : to)
   222→        do {
   223→            service.applyOrderedBonds(mutable)
   224→            try viewContext.save()
   225→        } catch {
   226→            print("❌ SvnrHybridView: reorder failed: \(error)")
   227→        }
   228→    }
   229→
   230→    // MARK: - Background loading
   231→
   232→    private func loadFavoriteBackground(screenSize: CGSize) {
   233→        guard let id = UUID(uuidString: favoriteSouvenirIDString) else {
   234→            favoriteBackgroundImage = nil
   235→            favoriteBackgroundAssetId = nil
   236→            SvnrPaletteStore.reset()
   237→            return
   238→        }
   239→        guard let souvenir = fetchSouvenir(id: id),
   240→              let assetId = souvenir.favoritePhoto?.assetLocalId else {
   241→            favoriteBackgroundImage = nil
   242→            favoriteBackgroundAssetId = nil
   243→            SvnrPaletteStore.reset()
   244→            return
   245→        }
   246→        guard assetId != favoriteBackgroundAssetId else { return }
   247→        favoriteBackgroundAssetId = assetId
   248→        Task {
   249→            let image = await photoLoader.loadPhoto(assetLocalId: assetId)
   250→            await MainActor.run {
   251→                favoriteBackgroundImage = image
   252→            }
   253→            if let image,
   254→               let accent = await ColorExtractionService.shared.extractDominantColor(from: image) {
   255→                let palette = SvnrPalette.derive(from: accent)
   256→                SvnrPaletteStore.setPalette(palette)
   257→            }
   258→            logBackgroundImage(image, assetId: assetId, screenSize: screenSize, scale: displayScale)
   259→        }
   260→    }
