   262→    private func logBackgroundImage(_ image: UIImage?, assetId: String, screenSize: CGSize, scale: CGFloat) {
   263→        let requiredWidth = screenSize.width * scale
   264→        let requiredHeight = screenSize.height * scale
   265→        if let image {
   266→            let imageWidth = image.size.width * image.scale
   267→            let imageHeight = image.size.height * image.scale
   268→            let suitable = imageWidth >= requiredWidth && imageHeight >= requiredHeight
   269→            print("🖼️ Hybrid background [\(assetId)] size: \(Int(imageWidth))x\(Int(imageHeight)) px | required: \(Int(requiredWidth))x\(Int(requiredHeight)) | suitable: \(suitable)")
   270→        } else {
