//
//  ViewsSvnrCapsuleRow.swift
//  souvenir
//
//  Wraps SouvenirCapsuleView with two context-sensitive swipe drawers.
//
//  Left drawer  (swipe right) = Communication drawer
//    - Boop button (always)
//    - Request Intro button (depth > 0: this person is not the user's direct contact)
//
//  Right drawer (swipe left) = Exploration drawer
//    - Branch button (navigate to contact's rings view)
//    - Drag handle button (same action as long-press: activate reorder)
//    - Only shown at depth == 0 (user's own HybridView); deeper trees hide it entirely.
//
//  Depth convention:
//    0 = user's own contacts list (HybridView)
//    1+ = someone else's tree (ContactRingsView and beyond)
//

import CoreData
import SwiftUI

struct SvnrCapsuleRow: View {

    // MARK: - Inputs

    let souvenir: SouvenirEntity
    @Binding var openRowID: UUID?
    let transitionNamespace: Namespace.ID
    let onSelect: () -> Void
    let onBoop: () -> Void
    let onTree: () -> Void
    let onRequestIntro: () -> Void
    /// 0 = user's own list; >0 = deeper tree. Controls drawer availability.
    var depth: Int = 0


    // MARK: - Drawer geometry

    private let drawerWidth: CGFloat = 68   // single column VStack, both drawers same width
    private let snapThreshold: CGFloat = 44

    // MARK: - Derived visibility

    private var showExploration: Bool { depth == 0 }
    private var showRequestIntro: Bool { depth > 0 }

    // MARK: - State

    /// Positive = slid right (communication drawer visible).
    /// Negative = slid left (exploration drawer visible; blocked when !showExploration).
    @State private var xOffset: CGFloat = 0
    @State private var dragStartOffset: CGFloat = 0
    @State private var isDragging: Bool = false
    @State private var showBoopToast: Bool = false
    @State private var containerWidth: CGFloat = 393

    // MARK: - Computed

    private var contactName: String {
        souvenir.primaryContact?.displayName ?? "this person"
    }

    private var isOpen: Bool { xOffset != 0 }

    // MARK: - Body

    var body: some View {
        ZStack(alignment: .center) {
            // Communication drawer — leading edge, revealed by right swipe
            communicationDrawer
                .frame(width: drawerWidth)
                .frame(maxHeight: .infinity)
                .offset(x: communicationDrawerXOffset)

            // Exploration drawer — trailing edge, revealed by left swipe (depth == 0 only)
            if showExploration {
                explorationDrawer
                    .frame(width: drawerWidth)
                    .frame(maxHeight: .infinity)
                    .offset(x: explorationDrawerXOffset)
            }

            // Capsule — hosts the sequenced long-press → drag gesture for reorder
            SouvenirCapsuleView(
                souvenir: souvenir,
                onSelect: {
                    if isOpen {
                        isDragging = false
                        xOffset = 0
                    } else {
                        onSelect()
                    }
                },
                transitionNamespace: transitionNamespace
            )
            .offset(x: xOffset)
            .gesture(reorderGesture)
        }
        .simultaneousGesture(isGrabbed ? nil : horizontalDrag)
        .animation(isDragging ? nil : .spring(response: 0.3, dampingFraction: 0.85), value: xOffset)
        .offset(y: displayOffset)
        .scaleEffect(isGrabbed ? 1.03 : 1.0, anchor: .center)
        .shadow(color: isGrabbed ? Color.black.opacity(0.18) : Color.clear, radius: isGrabbed ? 14 : 0)
        .zIndex(isGrabbed ? 1 : 0)
        .animation(.spring(response: 0.3, dampingFraction: 0.7), value: isGrabbed)
        .animation(.spring(response: 0.25, dampingFraction: 0.9), value: displayOffset)
        .clipped()
        .background(
            GeometryReader { geo in
                Color.clear.onAppear { containerWidth = geo.size.width }
            }
        )
        .onChange(of: openRowID) { _, newID in
            if newID != souvenir.id && isOpen {
                isDragging = false
                withAnimation(nil) { xOffset = 0 }
            }
        }
        .svnrToast(
            isPresented: $showBoopToast,
            text: "Booped \(contactName)",
            style: SvnrToastStyle(font: .subheadline.weight(.medium), color: .primary, background: .regularMaterial),
            placement: .top,
            icon: Image(systemName: "nose.fill"),
            duration: 1.8,
            haptic: true
        )
        .listRowInsets(EdgeInsets(top: 6, leading: 16, bottom: 6, trailing: 16))
        .listRowBackground(Color.clear)
        .listRowSeparator(.hidden)
    }

    // MARK: - Reorder gesture

    /// Long-press (0.45 s) then drag vertically to reorder.
    /// The sequencing ensures a quick horizontal swipe never accidentally lifts a row.
    private var reorderGesture: some Gesture {
        LongPressGesture(minimumDuration: 0.45)
            .sequenced(before: DragGesture(minimumDistance: 4))
            .onChanged { sequence in
                switch sequence {
                case .first(true):
                    // Long press complete — close drawer and signal start
                    isDragging = false
                    xOffset = 0
                    onReorderStart?()
                    UIImpactFeedbackGenerator(style: .medium).impactOccurred()
                case .second(_, let drag?):
                    onReorderUpdate?(drag.translation.height)
                default:
                    break
                }
            }
            .onEnded { sequence in
                switch sequence {
                case .second(_, let drag?):
                    onReorderEnd?(drag.translation.height)
                default:
                    onReorderEnd?(0)
                }
            }
    }

    // MARK: - Drawer offsets

    /// Communication drawer starts hidden left; slides in as capsule slides right.
    private var communicationDrawerXOffset: CGFloat {
        let hiddenCenter = -(containerWidth / 2 + drawerWidth / 2)
        let progress = min(max(xOffset / drawerWidth, 0), 1)
        return hiddenCenter + drawerWidth * progress
    }

    /// Exploration drawer starts hidden right; slides in as capsule slides left.
    private var explorationDrawerXOffset: CGFloat {
        let hiddenCenter = containerWidth / 2 + drawerWidth / 2
        let progress = min(max(-xOffset / drawerWidth, 0), 1)
        return hiddenCenter - drawerWidth * progress
    }

    // MARK: - Horizontal drag gesture

    private var horizontalDrag: some Gesture {
        DragGesture(minimumDistance: 12)
            .onChanged { value in
                let h = value.translation.width
                let v = value.translation.height
                guard abs(h) > abs(v) * 1.5 else { return }

                if !isDragging {
                    isDragging = true
                    dragStartOffset = xOffset
                    if openRowID != souvenir.id { openRowID = souvenir.id }
                }

                let raw = dragStartOffset + h
                // Block left swipe when exploration drawer is hidden
                let clampedRaw = showExploration ? raw : max(raw, 0)

                if clampedRaw < -drawerWidth {
                    let overshoot = -(clampedRaw + drawerWidth)
                    xOffset = -(drawerWidth + overshoot * 0.25)
                } else if clampedRaw > drawerWidth {
                    let overshoot = clampedRaw - drawerWidth
                    xOffset = drawerWidth + overshoot * 0.25
                } else {
                    xOffset = clampedRaw
                }
            }
            .onEnded { value in
                guard isDragging else { return }
                isDragging = false

                let h = value.translation.width
                let predicted = value.predictedEndTranslation.width
                let fastSwipe = abs(predicted - h) > 200

                let finalPosition = dragStartOffset + h
                if finalPosition > snapThreshold || (h > 0 && fastSwipe) {
                    xOffset = drawerWidth           // communication drawer
                } else if showExploration && (finalPosition < -snapThreshold || (h < 0 && fastSwipe)) {
                    xOffset = -drawerWidth          // exploration drawer
                } else {
                    xOffset = 0
                }
            }
    }

    // MARK: - Communication drawer (left side, swipe right)

    private var communicationDrawer: some View {
        VStack(spacing: 0) {
            Button {
                isDragging = false; xOffset = 0
                onBoop()
                showBoopToast = true
            } label: {
                drawerButtonLabel(systemImage: "nose", title: "Boop", color: .accentSvnr)
            }
            .tint(.accentSvnr)

            if showRequestIntro {
                Button {
                    isDragging = false; xOffset = 0
                    onRequestIntro()
                } label: {
                    drawerButtonLabel(systemImage: "person.fill.questionmark", title: "Request", color: .notedSvnr)
                }
                .tint(.notedSvnr)
            }
        }
        .background(.clear)
        .clipShape(RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.extraLarge, style: .continuous))
    }

    // MARK: - Exploration drawer (right side, swipe left, depth == 0 only)

    private var explorationDrawer: some View {
        VStack(spacing: 0) {
            Button {
                isDragging = false; xOffset = 0
                onTree()
            } label: {
                drawerButtonLabel(
                    systemImage: "arrow.trianglehead.branch",
                    title: "Branch",
                    color: .notedSvnr,
                    iconRotationDegrees: 90
                )
            }
            .tint(.notedSvnr)
        }
        .background(.clear)
        .clipShape(RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.extraLarge, style: .continuous))
    }

    // MARK: - Shared button label

    @ViewBuilder
    private func drawerButtonLabel(
        systemImage: String,
        title: String,
        color: Color,
        iconRotationDegrees: Double = 0
    ) -> some View {
        VStack(spacing: 6) {
            Image(systemName: systemImage)
                .font(.system(size: 20, weight: .medium))
                .rotationEffect(.degrees(iconRotationDegrees))
                .foregroundStyle(color)
            Text(title)
                .font(.caption2.weight(.medium))
                .foregroundStyle(color)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
    }
}

// MARK: - Preview

#Preview("CapsuleRow") {
    @Previewable @Namespace var ns
    @Previewable @State var openID: UUID? = nil
    let context = PersistenceController.preview.container.viewContext
    let request: NSFetchRequest<SouvenirEntity> = SouvenirEntity.fetchRequest()
    request.fetchLimit = 1
    if let s = try? context.fetch(request).first {
        return AnyView(
            List {
                SvnrCapsuleRow(
                    souvenir: s,
                    openRowID: $openID,
                    transitionNamespace: ns,
                    onSelect: {},
                    onBoop: {},
                    onTree: {},
                    onRequestIntro: {},
                    depth: 0
                )
            }
            .listStyle(.plain)
            .environment(\.managedObjectContext, context)
        )
    } else {
        return AnyView(Text("No preview souvenir"))
    }
}
